SELECT average_rating
FROM destinations
WHERE visited = 1;

SELECT destination_id, city, country, description, average_rating
FROM destinations
WHERE average_rating = (SELECT MAX(average_rating) FROM destinations);

SELECT city
FROM destinations
WHERE average_rating = (SELECT MAX(average_rating) FROM destinations);

SELECT AVG(average_rating) AS average_rating
FROM destinations
WHERE visited = 1 AND average_rating > 3.5;

SELECT COUNT(destination_id) AS visited_destinations
FROM travel_history
WHERE user_id = 1;

SELECT itinerary_name
FROM itineraries
WHERE status = 'completed';

SELECT AVG(average_rating) AS average_destination_rating
FROM destinations
WHERE destination_id IN (SELECT destination_id FROM reviews);
